<?php
namespace App\Models\Sales;
use App\Models\Inventory\Warehouse;use Illuminate\Database\Eloquent\Casts\Attribute;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;
class Shipment extends Model{use SoftDeletes; protected $fillable=['number','sale_id','customer_id','warehouse_id','dispatch_id','shipment_date','status','delivery_status','driver_name','vehicle_no','courier_name','tracking_number','notes','posted_by','posted_at','cancelled_by','cancelled_at','cancel_reason']; protected $casts=['shipment_date'=>'date','posted_at'=>'datetime','cancelled_at'=>'datetime']; protected $appends=['can_post','can_cancel','status_label'];
public function sale(){return $this->belongsTo(Sale::class);}public function customer(){return $this->belongsTo(Customer::class);}public function warehouse(){return $this->belongsTo(Warehouse::class);}public function lines(){return $this->hasMany(ShipmentLine::class);}protected function canPost(): Attribute{return Attribute::get(fn()=> $this->status==='draft');}protected function canCancel(): Attribute{return Attribute::get(fn()=> $this->status==='draft');}protected function statusLabel(): Attribute{return Attribute::get(fn()=>str($this->status)->replace('_',' ')->title()->toString());}}
